import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        decoded_str = decoded.decode('utf-8')
        token_data = json.loads(decoded_str)
    except (base64.binascii.Error, UnicodeDecodeError, ValueError):
        return None
    if isinstance(token_data, dict) and token_data.get('valid', False):
        return token_data.get('data', None)
    return None

